{"tool": "execute_python", "args": {"code": "import json
import re
from datetime import datetime

# Load German patents from 2019
de_patents_path = locals()['var_functions.query_db:26']
if isinstance(de_patents_path, str) and de_patents_path.endswith('.json'):
    with open(de_patents_path, 'r') as f:
        de_patents = json.load(f)
else:
    de_patents = de_patents_path

# Function to parse grant date to month
month_map = {
    'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6,
    'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12
}

def parse_grant_date(date_str):
    if not date_str:
        return None
    date_str = date_str.lower()
    # Extract month name
    for month_name, month_num in month_map.items():
        if month_name in date_str:
            # Check if it's 2019
            if '2019' in date_str:
                return month_num
    return None

# Function to extract CPC level 4 code (e.g., G06F9/45533 -> G06F9/455)
def get_cpc_level4(cpc_code):
    if not cpc_code:
        return None
    # Split by '/' to get the subclass and group
    parts = cpc_code.split('/')
    if len(parts) != 2:
        return None
    subclass = parts[0]
    group = parts[1]
    # Level 4 is the first 3 digits of the group (or less if group is shorter)
    if len(group) >= 3:
        level4_group = group[:3]
        return f"{subclass}/{level4_group}"
    else:
        return cpc_code

# Process patents
cpc_data = []
for patent in de_patents:
    grant_date = patent.get('grant_date', '')
    month = parse_grant_date(grant_date)

    # Skip if not in second half of 2019 (Jul-Dec)
    if not month or month < 7 or month > 12:
        continue

    # Parse CPC codes
    cpc_str = patent.get('cpc', '[]')
    try:
        cpc_list = json.loads(cpc_str)
    except:
        continue

    for cpc_item in cpc_list:
        code = cpc_item.get('code', '')
        level4_code = get_cpc_level4(code)
        if level4_code:
            cpc_data.append({
                'cpc_level4': level4_code,
                'month': month,
                'full_cpc': code
            })

# Count patents per CPC level 4 per month
cpc_month_counts = {}
for item in cpc_data:
    key = (item['cpc_level4'], item['month'])
    cpc_month_counts[key] = cpc_month_counts.get(key, 0) + 1

# Calculate EMA for each CPC level 4
# EMA formula: EMA_t = alpha * value_t + (1-alpha) * EMA_{t-1}
alpha = 0.1

# Get all unique CPC level 4 codes and months
cpc_codes = list(set(item['cpc_level4'] for item in cpc_data))
months = list(range(7, 13))  # July to December 2019

# Initialize EMA dictionary - we'll track EMA month by month for each CPC
cpc_ema = {cpc: {} for cpc in cpc_codes}

for cpc in cpc_codes:
    ema_prev = 0
    for month in months:
        # Get count for this month
        count = cpc_month_counts.get((cpc, month), 0)
        # Calculate EMA
        ema = alpha * count + (1 - alpha) * ema_prev
        cpc_ema[cpc][month] = ema
        ema_prev = ema

# Find CPC with highest EMA for each month
best_cpc_per_month = {}
for month in months:
    best_cpc = None
    best_ema = -1
    for cpc in cpc_codes:
        ema = cpc_ema[cpc].get(month, 0)
        if ema > best_ema:
            best_ema = ema
            best_cpc = cpc
    best_cpc_per_month[month] = {'cpc': best_cpc, 'ema': best_ema}

# Find best year (actually best month) for each CPC group
best_month_per_cpc = {}
for cpc in cpc_codes:
    best_month = None
    best_ema = -1
    for month in months:
        ema = cpc_ema[cpc].get(month, 0)
        if ema > best_ema:
            best_ema = ema
            best_month = month
    if best_month:
        month_names = {7: 'July', 8: 'August', 9: 'September', 10: 'October', 11: 'November', 12: 'December'}
        best_month_per_cpc[cpc] = {
            'best_month': month_names[best_month],
            'best_month_num': best_month,
            'best_ema': best_ema
        }

# Sort CPC groups by overall performance (max EMA)
sorted_cpc = sorted(best_month_per_cpc.items(), key=lambda x: x[1]['best_ema'], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'total_patents_processed': len(cpc_data),
    'unique_cpc_level4': len(cpc_codes),
    'best_cpc_per_month': best_cpc_per_month,
    'top_cpc_groups': sorted_cpc[:10]  # Top 10
}, indent=2, default=str))"}} <|tool_call_end|> <|tool_calls_section_end|>

